t.script:
                //
document.addEventListener('DOMContentLoaded', function() {
    // View toggle
    const kanbanBtn = document.getElementById('kanbanViewBtn');
    if (kanbanBtn) {
        kanbanBtn.addEventListener('click', function () {
            window.location.href = '/customer_support/tickets/kanban';
        });
    }

    // Search functionality
    const searchInput = document.getElementById('ticket-search');
    const statusFilter = document.getElementById('status-filter');
    const priorityFilter = document.getElementById('priority-filter');
    const ticketsList = document.getElementById('tickets-list');
    const clearSearchBtn = document.getElementById('clear-search');

    function filterTickets() {
        const searchTerm = searchInput.value.toLowerCase();
        const statusValue = statusFilter.value;
        const priorityValue = priorityFilter.value;

        if (ticketsList) {
            const ticketCards = ticketsList.querySelectorAll('.ticket-card');
            let visibleCount = 0;

            ticketCards.forEach(card => {
                const subjectEl = card.querySelector('.tl-subject');
                const title = subjectEl ? subjectEl.textContent.toLowerCase() : '';
                const ticketState = card.getAttribute('data-state') || '';
                const ticketPriority = card.getAttribute('data-priority') || '';

                const matchesSearch = searchTerm === '' || title.includes(searchTerm);
                const matchesStatus = statusValue === '' || ticketState === statusValue;
                const matchesPriority = priorityValue === '' || ticketPriority === priorityValue;

                const visible = matchesSearch && matchesStatus && matchesPriority;
                // Use class toggling — never touch inline display so CSS grid/flex is preserved
                card.classList.toggle('tl-filtered-out', !visible);
                if (visible) visibleCount++;
            });

            // Show / remove the empty state message
            const existingMsg = ticketsList.querySelector('.no-results-message');
            if (visibleCount === 0) {
                if (!existingMsg) {
                    const noResults = document.createElement('div');
                    noResults.className = 'empty-state no-results-message';
                    noResults.innerHTML = `
                        <div class="empty-state-icon">
                            <i class="bi bi-search"></i>
                        </div>
                        <h3 class="mb-3">No Tickets Found</h3>
                        <p class="text-muted mb-4">Try adjusting your search or filters</p>
                        <button class="btn btn-outline-primary" id="clear-filters">
                            Clear All Filters
                        </button>
                    `;
                    ticketsList.appendChild(noResults);
                    document.getElementById('clear-filters').addEventListener('click', function() {
                        searchInput.value = '';
                        statusFilter.value = '';
                        priorityFilter.value = '';
                        filterTickets();
                    });
                }
            } else {
                if (existingMsg) existingMsg.remove();
            }
        }
    }

    // Event listeners
    searchInput.addEventListener('input', filterTickets);
    statusFilter.addEventListener('change', filterTickets);
    priorityFilter.addEventListener('change', filterTickets);

    clearSearchBtn.addEventListener('click', function() {
        searchInput.value = '';
        statusFilter.value = '';
        priorityFilter.value = '';
        filterTickets();
    });

    // Make ticket cards open modal
    document.querySelectorAll('.ticket-card').forEach(card => {
        card.addEventListener('click', function(e) {
            if (!e.target.closest('a') && !e.target.closest('button')) {
                const ticketId = this.getAttribute('data-ticket-id');
                if (ticketId) openTicketModal(ticketId);
            }
        });
    });

});
//

    //
(function () {
    var overlay = document.getElementById('ticketModal');
    var loading = document.getElementById('tdmLoading');
    var content = document.getElementById('tdmContent');
    var currentTicketId = null;
    function escHtml(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
    function stripHtml(s){var d=document.createElement('div');d.innerHTML=String(s||'');return (d.textContent||d.innerText||'').trim();}
    function renderMessages(items){
        var host=document.getElementById('tdmMessages');
        if(!host) return;
        if(!items||!items.length){host.innerHTML='<div class="tdm-msg-empty">No messages yet.</div>';return;}
        host.innerHTML=items.map(function(m){
            var mine = m.is_me ? ' mine' : '';
            return '<div class="tdm-msg-row'+mine+'">'
                + '<div class="tdm-msg-bubble">'
                + '<div class="tdm-msg-head"><span class="tdm-msg-author">'+escHtml(m.is_me ? 'You' : (m.author||'Support'))+'</span><span class="tdm-msg-time">'+escHtml(m.date||'')+'</span></div>'
                + '<div class="tdm-msg-body">'+escHtml(stripHtml(m.body||''))+'</div>'
                + '</div>'
                + '</div>';
        }).join('');
        host.scrollTop = host.scrollHeight;
    }
    function closeModal(){overlay.style.display='none';document.body.style.overflow='';}
    function fillModal(data){
        var t=data.ticket;
        document.getElementById('tdmTicketNum').textContent=t.name;
        var sb=document.getElementById('tdmStateBadge');sb.textContent=t.state_label;sb.className='tdm-state-badge tdm-state-'+t.state;
        var pb=document.getElementById('tdmPriBadge');pb.textContent=t.priority.charAt(0).toUpperCase()+t.priority.slice(1);pb.className='tdm-pri-badge tdm-pri-'+t.priority;
        document.getElementById('tdmSubject').textContent=t.subject;
        document.getElementById('tdmAssigned').textContent=t.assigned_to;
        document.getElementById('tdmCreated').textContent=t.created;
        var sw=document.getElementById('tdmSlaWrap');
        if(t.sla_deadline){sw.style.display='flex';sw.className='tdm-meta-item tdm-sla-'+t.sla_status;document.getElementById('tdmSla').textContent='SLA: '+t.sla_deadline;}else{sw.style.display='none';}
        document.getElementById('tdmDescription').textContent=t.description||'No description provided.';
        var bs=document.getElementById('tdmBoardSection');
        if(data.board_total>0){
            bs.style.display='';
            var pct=data.board_progress;
            document.getElementById('tdmProgressPct').textContent=data.board_done+'/'+data.board_total+' · '+pct+'%';
            var fill=document.getElementById('tdmProgressFill');fill.style.width=pct+'%';fill.className='tdm-progress-fill'+(pct===100?' done':'');
            var ch='';
            (data.board_columns||[]).forEach(function(col){
                ch+='<div class="tdm-col"><div class="tdm-col-head" style="border-left:3px solid '+escHtml(col.color)+'">';
                ch+='<span class="tdm-col-name">'+escHtml(col.name)+'</span><span class="tdm-col-count">'+col.done_count+'/'+col.task_count+'</span></div>';
                if(col.tasks&&col.tasks.length){ch+='<div class="tdm-col-tasks">';col.tasks.forEach(function(task){ch+='<div class="tdm-task'+(task.is_done?' tdm-task-done':'')+'"><i class="bi '+(task.is_done?'bi-check-circle-fill':'bi-circle')+'"></i><span class="tdm-task-name">'+escHtml(task.name)+'</span></div>';});ch+='</div>';}
                else{ch+='<div class="tdm-col-empty">No tasks</div>';}
                ch+='</div>';
            });
            document.getElementById('tdmCols').innerHTML=ch;
        }else{bs.style.display='none';}

        renderMessages(data.messages || []);
    }
    window.openTicketModal=function(ticketId){
        currentTicketId = ticketId;
        overlay.style.display='flex';document.body.style.overflow='hidden';
        loading.style.display='flex';content.style.display='none';
        var ri = document.getElementById('tdmReplyInput');
        if (ri) ri.value = '';
        fetch('/customer_support/customer/ticket/'+ticketId+'/data',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({jsonrpc:'2.0',method:'call',id:1,params:{}})})
        .then(function(r){return r.json();}).then(function(resp){
            var d=resp.result||{};
            if(!d.success){loading.innerHTML='<i class="bi bi-exclamation-circle" style="font-size:1.5rem;color:#ef4444"></i><span>'+escHtml(d.error||'Failed to load')+'</span>';return;}
            fillModal(d);loading.style.display='none';content.style.display='';
        }).catch(function(){loading.innerHTML='<i class="bi bi-wifi-off" style="font-size:1.5rem;color:#ef4444"></i><span>Network error</span>';});
    };

    var sendBtn = document.getElementById('tdmReplySend');
    var replyInput = document.getElementById('tdmReplyInput');
    if (sendBtn && replyInput) {
        sendBtn.addEventListener('click', function(){
            var msg = (replyInput.value || '').trim();
            if (!currentTicketId || !msg) return;
            sendBtn.disabled = true;
            fetch('/customer_support/customer/ticket/' + currentTicketId + '/message/add', {
                method:'POST',
                headers:{'Content-Type':'application/json'},
                body:JSON.stringify({jsonrpc:'2.0',method:'call',id:1,params:{message:msg}})
            })
            .then(function(r){ return r.json(); })
            .then(function(resp){
                var d = resp.result || {};
                if (!d.success) return;
                replyInput.value = '';
                // Refresh ticket modal data to keep message list and board state in sync.
                return fetch('/customer_support/customer/ticket/' + currentTicketId + '/data', {
                    method:'POST',
                    headers:{'Content-Type':'application/json'},
                    body:JSON.stringify({jsonrpc:'2.0',method:'call',id:1,params:{}})
                }).then(function(r){ return r.json(); }).then(function(ref){
                    var rd = ref.result || {};
                    if (rd.success) fillModal(rd);
                });
            })
            .finally(function(){ sendBtn.disabled = false; });
        });
    }
    document.getElementById('tdmClose').addEventListener('click',closeModal);
    document.getElementById('tdmCloseBtn').addEventListener('click',closeModal);
    overlay.addEventListener('click',function(e){if(e.target===overlay)closeModal();});
    document.addEventListener('keydown',function(e){if(e.key==='Escape')closeModal();});
})();
//

    //
(function () {
    var bell      = document.getElementById('ticketsNotifBell');
    var dropdown  = document.getElementById('ticketsNotifDropdown');
    var badge     = document.getElementById('ticketsNotifBadge');
    var notifList = document.getElementById('ticketsNotifList');
    if (bell && dropdown) {
        bell.addEventListener('click', function (e) { e.stopPropagation(); dropdown.classList.toggle('open'); });
        document.addEventListener('click', function () { dropdown.classList.remove('open'); });
        dropdown.addEventListener('click', function (e) { e.stopPropagation(); });
    }
    var markReadBtn = document.getElementById('ticketsMarkRead');
    if (markReadBtn) {
        markReadBtn.addEventListener('click', function () {
            fetch('/customer_support/customer/notifications/mark_read', { method: 'POST', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
            .then(function () {
                if (badge) { badge.classList.add('d-none'); badge.textContent = '0'; }
                if (notifList) { notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>All caught up!</div>'; }
            });
        });
    }
    function sanitise(str) { var d = document.createElement('div'); d.textContent = String(str || ''); return d.innerHTML; }
    function renderNotifications(items) {
        if (!notifList) return;
        if (!items || !items.length) {
            notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>No new notifications</div>';
            if (badge) badge.classList.add('d-none');
            return;
        }
        if (badge) { badge.textContent = items.length; badge.classList.remove('d-none'); }
        var typeLabels = { status_change: 'Status Update', assigned: 'Assigned', sla_breach: 'SLA Breach' };
        notifList.innerHTML = items.map(function (n) {
            var cls        = sanitise(n.cls   || 'status');
            var icon       = sanitise(n.icon  || 'bi-bell-fill');
            var ticketName = sanitise(n.ticket_name || (n.ticket_id ? '#' + n.ticket_id : ''));
            var typeLabel  = sanitise(typeLabels[n.type] || 'Notification');
            var msg        = sanitise(n.message || '');
            var time       = sanitise(n.time   || '');
            var title      = ticketName ? ticketName + ' \u00b7 ' + typeLabel : typeLabel;
            return '<div class="notif-item">'
                + '<div class="notif-icon-wrap ' + cls + '"><i class="bi ' + icon + '"></i></div>'
                + '<div class="notif-body">'
                + '<div class="notif-title">' + title + '</div>'
                + '<div class="notif-sub">' + msg + '</div>'
                + '<div class="notif-time-text">' + time + '</div>'
                + '</div>'
                + '<div class="notif-dot ' + cls + '"></div>'
                + '</div>';
        }).join('');
    }
    function loadNotifications() {
        fetch('/customer_support/customer/notifications', { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { return r.json(); })
        .then(function (data) { renderNotifications(data.notifications || []); })
        .catch(function () { renderNotifications([]); });
    }
    loadNotifications();
    setInterval(loadNotifications, 30000);
})();
